function o(e){if(e===null||e<=0)return"-";const t=Math.ceil(e/1e3);if(t<60)return`${t}s`;const r=Math.floor(t/60),n=t%60;return n===0?`${r}m`:`${r}m${n}s`}function a(e){return e?new Date(e).toLocaleTimeString("zh-CN",{hour12:!1}):"--:--:--"}function u(e){if(!e)return"-";const t=new Date(e);if(Number.isNaN(t.getTime()))return e;const r=n=>String(n).padStart(2,"0");return`${t.getFullYear()}-${r(t.getMonth()+1)}-${r(t.getDate())} ${r(t.getHours())}:${r(t.getMinutes())}:${r(t.getSeconds())}`}export{o as a,u as b,a as f};
